.load extensions/id3/target/wasm32-wasip2/release/id3_extension.component.wasm

/* ID3 tag parsing.
 *
 * Per PLAN-more-extensions-4.md  2 acceptance:
 *   - ID3v2 fixture with known tags: every field extracts
 *   - ID3v1 fixture (128-byte trailer): basic fields extract,
 *     v2-only fields (album_artist / composer / disc) -> NULL
 *   - Random bytes  every fn returns NULL (no error)
 *   - id3_version reports "ID3v2.4" / "ID3v2.3" / "ID3v1"
 *
 * Fixtures (all hex literals  built by writing the id3 crate's
 * Tag::write_to into a buffer; see the section header in lib.rs):
 *
 *   v24:  202-byte ID3v2.4 envelope. Title=Test Title, Artist=Test
 *         Artist, Album=Test Album, AlbumArtist=Test AArt, Year=2024,
 *         Genre=Synthwave, Track=5/10, Disc=1/2, Composer=Test
 *         Composer, Comment="Hello" in eng.
 *
 *   v23:  126-byte ID3v2.3 envelope with UTF-16 text encoding. Title=
 *         Title v23, Artist=Artist v23, Album=Album v23, Year=2020.
 *         No other frames  v23 specific UTF-16 BOM + null-terminator
 *         handling tested here.
 *
 *   v1:   hand-assembled 128-byte ID3v1.1 trailer. Title=V1 Title,
 *         Artist=V1 Artist, Album=V1 Album, Year=1999, Comment=
 *         V1 Comment, Track=7, GenreId=18 (Techno per the Winamp list).
 *
 *   random:  12 bytes of 0xAA  no v2 prefix, too short for v1.
 *
 *   v1pad:  same as v1 prefixed with 256 zero bytes  exercises the
 *           v1 trailer-scan path with non-trivial leading content.
 */

------------------------------------------------------------------
-- Acceptance 1: ID3v2.4 fixture -> every named field extracts
------------------------------------------------------------------
SELECT id3_title(x'');
SELECT id3_artist(x'');
SELECT id3_album(x'');
SELECT id3_year(x'');
SELECT id3_genre(x'');
SELECT id3_track(x'');
SELECT id3_disc(x'');
SELECT id3_comment(x'');
SELECT id3_album_artist(x'');
SELECT id3_composer(x'');
SELECT id3_version(x'');

------------------------------------------------------------------
-- Acceptance 2: id3_all is valid JSON, spot-check via json_extract
------------------------------------------------------------------
SELECT json_extract(id3_all(x''), '$.TIT2');
SELECT json_extract(id3_all(x''), '$._version');

------------------------------------------------------------------
-- Acceptance 3: ID3v2.3 fixture parses (UTF-16 text encoding)
------------------------------------------------------------------
SELECT id3_title(x'494433030000000000745449543200000015000001FFFE5400690074006C00650020007600320033005450453100000017000001FFFE410072007400690073007400200076003200330054414C4200000015000001FFFE41006C00620075006D002000760032003300545945520000000B000001FFFE3200300032003000');
SELECT id3_artist(x'494433030000000000745449543200000015000001FFFE5400690074006C00650020007600320033005450453100000017000001FFFE410072007400690073007400200076003200330054414C4200000015000001FFFE41006C00620075006D002000760032003300545945520000000B000001FFFE3200300032003000');
SELECT id3_album(x'494433030000000000745449543200000015000001FFFE5400690074006C00650020007600320033005450453100000017000001FFFE410072007400690073007400200076003200330054414C4200000015000001FFFE41006C00620075006D002000760032003300545945520000000B000001FFFE3200300032003000');
SELECT id3_year(x'494433030000000000745449543200000015000001FFFE5400690074006C00650020007600320033005450453100000017000001FFFE410072007400690073007400200076003200330054414C4200000015000001FFFE41006C00620075006D002000760032003300545945520000000B000001FFFE3200300032003000');
SELECT id3_version(x'494433030000000000745449543200000015000001FFFE5400690074006C00650020007600320033005450453100000017000001FFFE410072007400690073007400200076003200330054414C4200000015000001FFFE41006C00620075006D002000760032003300545945520000000B000001FFFE3200300032003000');

------------------------------------------------------------------
-- Acceptance 4: ID3v1 trailer  basic fields extract, v2-only NULL
-- (128-byte trailer prefixed with 256 NUL bytes so the v1 path is
-- the only viable parse  pure v1 file).
------------------------------------------------------------------
SELECT id3_title(x'');
SELECT id3_artist(x'');
SELECT id3_album(x'');
SELECT id3_year(x'');
SELECT id3_comment(x'');
SELECT id3_track(x'');
SELECT id3_genre(x'');
SELECT id3_version(x'');

-- v2-only fields on a v1 tag  NULL
SELECT id3_album_artist(x'');
SELECT id3_composer(x'');
SELECT id3_disc(x'');
SELECT id3_duration_ms(x'');

------------------------------------------------------------------
-- Acceptance 5: random bytes -> NULL on every fn (no error)
------------------------------------------------------------------
SELECT id3_title(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_artist(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_album(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_year(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_genre(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_track(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_disc(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_comment(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_album_artist(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_composer(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_duration_ms(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_version(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT id3_all(x'AAAAAAAAAAAAAAAAAAAAAAAA');

------------------------------------------------------------------
-- Acceptance 6: NULL input -> NULL on every fn
------------------------------------------------------------------
SELECT id3_title(NULL);
SELECT id3_year(NULL);
SELECT id3_all(NULL);

------------------------------------------------------------------
-- Acceptance 7: id3_meta_version is non-empty TEXT
------------------------------------------------------------------
SELECT length(id3_meta_version()) > 0;
